const product = $('Fetch Product Info').first().json;
const video = $('Fetch Video Info').first().json;
const name = product.product_name || product.name || video.product_name || video.title || 'Sản phẩm BongBanViet';
const price = product.price ? `Giá: ${Number(product.price).toLocaleString('vi-VN')} VND` : '';
const description = [
  `${name} — gợi ý nhanh cho người chơi bóng bàn`,
  product.description || video.description || '',
  price,
  'Đặt hàng trên TikTok Shop và nhận tư vấn setup phù hợp.',
  '#BongBanViet #TikTokShop #BongBan'
].filter(Boolean).join('\n');
return [{ json: { product, video, tiktok_shop_description: description } }];

const input = $input.first().json;
const p = input.product || {};
const v = input.video || {};
const mapped = {
  product_name: (p.product_name || p.name || v.product_name || v.title || '').slice(0, 255),
  description: input.tiktok_shop_description,
  price: Number(p.price || 0),
  stock: Number(p.stock || 0),
  images: Array.isArray(p.images) ? p.images.map(String).filter(Boolean) : [],
  video_url: v.video_url || p.video_url || '',
  sku: String(p.sku || p.source_id || v.source_id || ''),
  category: String(p.category || ''),
  source_id: String(p.source_id || v.source_id || '')
};
const errors = [];
if (!mapped.product_name) errors.push('product_name bắt buộc');
if (mapped.price <= 0) errors.push('price phải dương');
if (!mapped.sku) errors.push('sku bắt buộc');
if (errors.length) throw new Error(`Dữ liệu không hợp lệ: ${errors.join(', ')}`);
return [{ json: mapped }];

const fs = require('fs');
const path = require('path');
const input = $input.first().json;

const sourceId = input.source_id || input.sku || `tts-${Date.now()}`;
const date = new Date().toISOString().slice(0, 10);
const safeId = sourceId.replace(/[^a-zA-Z0-9_-]/g, '_').slice(0, 40);
const basename = `tiktok-shop-${date}-${safeId}`;
const outputDir = path.join(process.cwd(), 'output');
fs.mkdirSync(outputDir, { recursive: true });

const checklist = [
  'Vào TikTok Seller Centre → Sản phẩm → Thêm sản phẩm mới',
  'Điền tên sản phẩm (product_name)',
  'Chọn danh mục phù hợp với category_hint',
  'Upload ảnh sản phẩm từ danh sách images',
  'Upload video sản phẩm nếu có (video_url)',
  'Điền mô tả (description)',
  'Thêm biến thể: điền SKU, giá, tồn kho',
  'Thiết lập vận chuyển',
  'Xem lại → Gửi duyệt'
];

const jsonData = {
  channel: 'tiktok-shop',
  generated_at: new Date().toISOString(),
  source_id: sourceId,
  listing: {
    product_name: input.product_name,
    description: input.description,
    price_vnd: input.price,
    stock: input.stock,
    seller_sku: input.sku,
    category_hint: input.category,
    images: input.images,
    video_url: input.video_url || null
  },
  checklist
};

const imageList = (input.images || []).map((u, i) => `${i+1}. ${u}`).join('\n') || '—';

const md = [
  `# TikTok Shop Draft — ${date}`,
  '',
  '## Thông tin sản phẩm',
  '',
  '| Trường | Giá trị |',
  '|--------|---------|',
  `| Source ID | \`${sourceId}\` |`,
  `| SKU | \`${input.sku}\` |`,
  `| Tên sản phẩm | ${input.product_name} |`,
  `| Giá (VND) | ${Number(input.price).toLocaleString('vi-VN')} |`,
  `| Tồn kho | ${input.stock} |`,
  `| Danh mục gợi ý | ${input.category || '—'} |`,
  `| Video | ${input.video_url ? input.video_url : '—'} |`,
  `| Tạo lúc | ${new Date().toLocaleString('vi-VN')} |`,
  '',
  '## Mô tả (copy vào TikTok Shop)',
  '',
  '```',
  input.description,
  '```',
  '',
  '## Ảnh sản phẩm',
  '',
  imageList,
  '',
  '## Checklist đăng thủ công',
  '',
  checklist.map((s, i) => `${i+1}. ${s}`).join('\n')
].join('\n');

fs.writeFileSync(path.join(outputDir, `${basename}.json`), JSON.stringify(jsonData, null, 2));
fs.writeFileSync(path.join(outputDir, `${basename}.md`), md);

return [{ json: { channel: 'tiktok-shop', mode: 'draft', source_id: sourceId, sku: input.sku, json_file: `output/${basename}.json`, md_file: `output/${basename}.md`, generated_at: jsonData.generated_at } }];

const result = $input.first().json;
const webhook = $env.SOURCE_RESULT_WEBHOOK_URL;
if (webhook) {
  const res = await fetch(webhook, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(result)
  });
  if (!res.ok) console.warn('Result webhook failed', res.status);
}
return [{ json: { ...result, notified: !!webhook, saved_at: new Date().toISOString() } }];

const error = $execution.error || {};
const webhook = $env.SOURCE_RESULT_WEBHOOK_URL;
const payload = { channel: 'tiktok-shop', ok: false, error: error.message || 'Unknown error', time: new Date().toISOString() };
if (webhook) {
  await fetch(webhook, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(payload) }).catch(() => {});
}
return [{ json: payload }];
